422: void DecodingProcessorState::clearRouteCache(const CommonResponse& common_response) {
423:   if (!common_response.clear_route_cache()) {
424:     return;
425:   }
426:   if (filter_.config().isUpstream()) {
427:     filter_.stats().clear_route_cache_upstream_ignored_.inc();
428:     ENVOY_LOG(debug, "NOT clearing route cache. The filter is in upstream filter chain.");
429:     return;
430:   }
431:   // Only clear the route cache if there is a mutation to the header and clearing is allowed.
432:   if (filter_.config().disableClearRouteCache()) {
433:     filter_.stats().clear_route_cache_disabled_.inc();
434:     ENVOY_LOG(debug, "NOT clearing route cache, it is disabled in the config");
435:     return;
436:   }
437:   if (common_response.has_header_mutation()) {
438:     ENVOY_LOG(debug, "clearing route cache");
439:     decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
440:     return;
441:   }
442:   filter_.stats().clear_route_cache_ignored_.inc();
443:   ENVOY_LOG(debug, "NOT clearing route cache, no header mutations detected");
444: }
