446: void EncodingProcessorState::setProcessingModeInternal(const ProcessingMode& mode) {
447:   // Account for the different default behaviors of headers and trailers --
448:   // headers are sent by default and trailers are not.
449:   send_headers_ = mode.response_header_mode() != ProcessingMode::SKIP;
450:   send_trailers_ = mode.response_trailer_mode() == ProcessingMode::SEND;
451:   setBodyMode(mode.response_body_mode());
452: }
