454: void EncodingProcessorState::requestWatermark() {
455:   if (!watermark_requested_) {
456:     ENVOY_LOG(debug, "Watermark raised on encoding");
457:     watermark_requested_ = true;
458:     encoder_callbacks_->onEncoderFilterAboveWriteBufferHighWatermark();
459:   }
